CREATE TABLE IF NOT EXISTS public.user_profiles ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL UNIQUE REFERENCES auth.users(id) ON DELETE CASCADE, plan VARCHAR(255) DEFAULT 'starter', stripe_customer_id VARCHAR(255) UNIQUE, stripe_subscription_id VARCHAR(255) UNIQUE, stripe_price_id VARCHAR(255), subscription_status VARCHAR(255) DEFAULT 'trialing', trial_ends_at TIMESTAMPTZ DEFAULT (now() + '14 days'::interval), created_at TIMESTAMPTZ DEFAULT now(), updated_at TIMESTAMPTZ DEFAULT now()); INSERT INTO public.user_profiles (user_id, plan, subscription_status, trial_ends_at) SELECT om.user_id, o.plan, o.subscription_status, o.trial_ends_at FROM public.org_members om JOIN public.organizations o ON om.organization_id = o.id WHERE om.role = 'owner' ON CONFLICT (user_id) DO NOTHING;
